spec.inputArgumentsSchemaV2:
{
  "type": "object",
  "required": [
    "emailFrom",
    "emailSubject",
    "emailBody"
  ],
  "properties": {
    "emailFrom": {
      "type": "string",
      "description": "Sender of the complaint email (display name and/or address). Used to help identify the complaining customer."
    },
    "emailSubject": {
      "type": "string",
      "description": "Subject line of the complaint email."
    },
    "emailBody": {
      "type": "string",
      "description": "Full plain-text body of the complaint email."
    }
  }
}

spec.outputArgumentsSchemaV2:
{
  "type": "object",
  "required": [
    "customerName",
    "productName",
    "batchNo",
    "orderNo",
    "complaintSummary",
    "confidence",
    "qtyAffected",
    "extractedType"
  ],
  "properties": {
    "customerName": {
      "type": "string",
      "description": "The complaining B2B organisation as written (company / pharmacy / hospital / wholesaler). Falls back to the sender's organisation or email domain. Empty string if undeterminable."
    },
    "productName": {
      "type": "string",
      "description": "The affected medicinal product (brand or generic name), including strength and form if stated. Empty string if undeterminable."
    },
    "batchNo": {
      "type": "string",
      "description": "The batch / lot number of the affected product, e.g. in the form P###-B## (P001-B01). Empty string if not present."
    },
    "orderNo": {
      "type": "string",
      "description": "The sales-order reference, e.g. in the form SO-#### (SO-1001). Empty string if not present."
    },
    "complaintSummary": {
      "type": "string",
      "description": "One plain-language sentence capturing the complaint: product/batch, customer, and the core issue."
    },
    "confidence": {
      "type": "number",
      "description": "Confidence in the extraction and classification, from 0 (low) to 1 (high)."
    },
    "qtyAffected": {
      "type": "integer",
      "description": "Number of affected units. For quantity discrepancies, the absolute difference |ordered - received|. 0 when no quantity can be determined."
    },
    "extractedType": {
      "type": "string",
      "description": "The complaint category. Exactly one of: QuantityDiscrepancy (a mismatch between ordered and received quantities), ColdChain (a temperature-logger / cold-chain problem in transport), QualityDeficit (a transport-caused defect that makes the product unsellable), or Other (none of the three).",
      "enum": [
        "QuantityDiscrepancy",
        "ColdChain",
        "QualityDeficit",
        "Other"
      ]
    }
  }
}

